58	/**
59	 * Truncate `value` to at most `maxBytes` UTF-8 bytes (including a
60	 * trailing ellipsis). Uses TextEncoder.encode() length so multibyte
61	 * content (CJK, emoji) doesn't sneak past the cap. Binary-searches the
62	 * code-unit cut point; correct for surrogate pairs because slice() on
63	 * a string never splits a pair when called at a non-low-surrogate
64	 * position — and the binary search converges on a value where the
65	 * encoded length is <= maxBytes, so any split that would have produced
66	 * an unpaired surrogate is naturally rejected.
67	 *
68	 * Edge case: if maxBytes < 3 (smaller than the UTF-8 ellipsis itself),
69	 * return empty string. In practice MAX is 64 KiB so this never triggers,
70	 * but the guard keeps the function robust.
71	 */
72	function truncateUtf8(value: string, maxBytes: number): string {
73	  const enc = new TextEncoder();
74	  if (enc.encode(value).length <= maxBytes) return value;
75	  if (maxBytes < 3) return '';
76	  let lo = 0;
77	  let hi = value.length;
78	  while (lo < hi) {
79	    const mid = Math.ceil((lo + hi) / 2);
80	    if (enc.encode(`${value.slice(0, mid)}…`).length <= maxBytes) lo = mid;
81	    else hi = mid - 1;
82	  }
83	  return `${value.slice(0, lo)}…`;
84	}
85	
86	function rowToRoutine(row: {
87	  agent_id: string; path: string; author_user_id: string;
