11	export interface FireResult {
12	  status: FireStatus;
13	  conversationId?: string | null;
14	  error: string | null;
15	  /**
16	   * The prompt that was actually rendered and sent to the agent.
17	   * `null` when fireRoutine returned before reaching the render step
18	   * (e.g., agents:resolve or conversations:create failed). Non-null on
19	   * `'ok'` and `'silenced'`, and on `'error'` paths that errored after
20	   * rendering.
21	   */
22	  renderedPrompt: string | null;
23	}
24	
25	export type FireRoutineFn = (
26	  row: RoutineRow,
27	  source: 'tick' | 'manual',
28	) => Promise<FireResult>;
29	
30	export interface TickOnceInput {
31	  store: RoutinesStore;
32	  fire: FireRoutineFn;
33	  now: Date;
34	  claimBatchSize: number;
35	  claimWindowMinutes: number;
36	}
37	
38	export async function runTickOnce(input: TickOnceInput): Promise<void> {
39	  const claimed = await input.store.claimDue({
40	    now: input.now,
41	    limit: input.claimBatchSize,
42	    claimWindowMinutes: input.claimWindowMinutes,
43	  });
44	
45	  for (const row of claimed) {
46	    if (row.activeHours !== null) {
47	      const adjusted = advanceToNextActiveWindow(input.now, row.activeHours);
48	      if (adjusted.getTime() > input.now.getTime()) {
49	        await input.store.advance({
50	          agentId: row.agentId, path: row.path,
51	          nextRunAt: adjusted,
52	          lastRunAt: input.now,
53	          lastStatus: row.lastStatus ?? 'ok',
54	          lastError: row.lastError ?? null,
55	        });
56	        continue;
57	      }
58	    }
59	
60	    let result: FireResult;
61	    try {
62	      result = await input.fire(row, 'tick');
63	    } catch (err) {
64	      const msg = err instanceof Error ? err.message : String(err);
65	      result = { status: 'error', error: msg, conversationId: null, renderedPrompt: null };
66	    }
67	
68	    await input.store.recordFire({
69	      agentId: row.agentId, path: row.path,
70	      triggerSource: 'tick',
71	      conversationId: result.conversationId ?? null,
72	      status: result.status,
73	      error: result.error,
74	      renderedPrompt: result.renderedPrompt,
75	    });
76	
77	    // row.nextRunAt has been bumped by claimWindowMinutes by claimDue; recover the
78	    // original scheduled time so drift control advances from the right baseline.
79	    const claimOffsetMs = input.claimWindowMinutes * 60 * 1000;
80	    const originalNextRunAt = row.nextRunAt != null
81	      ? new Date(row.nextRunAt.getTime() - claimOffsetMs)
82	      : null;
83	    const nextAt = computeNextRunAt(row, originalNextRunAt, input.now);
84	    await input.store.advance({
85	      agentId: row.agentId, path: row.path,
86	      nextRunAt: nextAt,
87	      lastRunAt: input.now,
88	      lastStatus: result.status,
89	      lastError: result.error,
90	    });
91	  }
92	}
93	
94	function computeNextRunAt(row: RoutineRow, originalNextRunAt: Date | null, now: Date): Date | null {
95	  if (row.trigger.kind === 'webhook') return null;
96	  const eng = engineFor(row.trigger);
97	  if (eng === null) return null;
98	
99	  if (row.trigger.kind === 'interval') {
100	    const seconds = durationToSeconds(row.trigger.every) ?? 0;
101	    const prevTarget = originalNextRunAt ?? now;
102	    const candidate = new Date(prevTarget.getTime() + seconds * 1000);
103	    const isMoreThanOneBehind =
104	      now.getTime() - prevTarget.getTime() > seconds * 1000;
105	    const oneIntervalAhead = new Date(now.getTime() + seconds * 1000);
106	    return isMoreThanOneBehind ? oneIntervalAhead : candidate;
107	  }
108	
109	  return eng.nextRun(row.trigger, now);
110	}
111	
112	export interface TickLoopInput {
113	  db: Kysely<RoutinesDatabase>;
114	  fire: FireRoutineFn;
115	  clock: Clock;
116	  signal: AbortSignal;
117	  tickIntervalMs: number;
118	  electionRetryMs: number;
119	  claimBatchSize: number;
120	  claimWindowMinutes: number;
121	}
122	
123	const ADVISORY_LOCK_KEY = 'ax/routines.tick';
124	
125	export async function runTickLoop(input: TickLoopInput): Promise<void> {
126	  while (!input.signal.aborted) {
127	    // Connection-pin the elected ticker's whole lifetime. Both the advisory
128	    // lock and the store ops it gates must run on the same backend session
129	    // (pg_try_advisory_lock is session-scoped, and routing store ops to
130	    // other pool connections would self-deadlock when pool.max === 1 since
131	    // the only free connection is the one we just pinned).
132	    //
133	    // Losing replicas DO NOT sleep inside execute() — they return early so
134	    // the connection rejoins the pool during electionRetryMs backoff,
135	    // keeping idle backend count = (active tickers), not (replica count).
136	    const acquired = await input.db.connection().execute(async (pinned) => {
137	      const locked = await tryAcquireAdvisoryLock(pinned);
138	      if (!locked) return false;
139	      const pinnedStore = createRoutinesStore(pinned);
140	      try {
141	        while (!input.signal.aborted) {
142	          try {
143	            await runTickOnce({
144	              store: pinnedStore, fire: input.fire,
145	              now: input.clock.now(),
146	              claimBatchSize: input.claimBatchSize,
147	              claimWindowMinutes: input.claimWindowMinutes,
148	            });
149	          } catch (err) {
150	            process.stderr.write(
151	              `[ax/routines] tick error: ${err instanceof Error ? err.message : String(err)}\n`,
152	            );
153	          }
154	          await input.clock.sleep(input.tickIntervalMs, input.signal);
155	        }
156	      } finally {
157	        await releaseAdvisoryLock(pinned);
158	      }
159	      return true;
160	    });
161	
162	    if (!acquired) {
163	      await input.clock.sleep(input.electionRetryMs, input.signal);
164	    }
165	  }
166	}
167	
168	async function tryAcquireAdvisoryLock(db: Kysely<RoutinesDatabase>): Promise<boolean> {
169	  const r = await sql<{ ok: boolean }>`
170	    SELECT pg_try_advisory_lock(hashtext(${ADVISORY_LOCK_KEY})) AS ok
171	  `.execute(db);
172	  return r.rows[0]?.ok === true;
173	}
174	
175	async function releaseAdvisoryLock(db: Kysely<RoutinesDatabase>): Promise<void> {
176	  try {
177	    await sql`SELECT pg_advisory_unlock(hashtext(${ADVISORY_LOCK_KEY}))`.execute(db);
178	  } catch {
179	    // disconnect handles it
180	  }
181	}
