import {
  makeAgentContext,
  PluginError,
  type AgentContext,
  type HookBus,
} from '@ax/core';
import { z } from 'zod';
import {
  parseRequestBody,
  requireUser,
  writeServiceError,
  type RouteRequest,
  type RouteResponse,
} from './shared.js';

// ---------------------------------------------------------------------------
// /settings/routines* — owner-scoped HTTP surface for the Routines admin UI.
//
// Three routes:
//
//   GET  /settings/routines
//   GET  /settings/routines/:agentId/fires?path=<routine-path>&limit=<n>
//   POST /settings/routines/:agentId/fire   { path, payload? }
//
// Every route:
//   1. Calls `auth:require-user` (401 if no session).
//   2. ACL-gates by calling `agents:resolve({ agentId, userId: actor.id })` —
//      if that throws (forbidden / not-found) the route returns 403. This is
//      the L8 enforcement: every entry point validates the owner before
//      reaching the routines facade.
//   3. Delegates to the routines service hooks.
//
// No cross-plugin imports per Invariant L2 — RouteRequest/RouteResponse are
// duck-typed in ./shared.js and the routines/agents shapes are inlined
// locally as zod schemas / generic types.
// ---------------------------------------------------------------------------

const PLUGIN_NAME = '@ax/routines-admin-routes';

/** POST /settings/routines/:agentId/fire body shape. Strict — extra fields
 *  reject so a confused client doesn't slip a `source` override past us. */
const fireBodySchema = z
  .object({
    path: z.string().min(1).max(512),
    payload: z.unknown().optional(),
  })
  .strict();

export interface AdminDeps {
  bus: HookBus;
}

/** AgentContext for a request executing on behalf of `actorId`. The sessionId
 *  is fixed (`routines-admin`) — these handlers are stateless from the bus's
 *  perspective, the value just shows up in logs. */
function ctxForActor(actorId: string): AgentContext {
  return makeAgentContext({
    sessionId: 'routines-admin',
    agentId: PLUGIN_NAME,
    userId: actorId,
  });
}

/** True if `userId` can resolve `agentId`. `agents:resolve` does the
 *  visibility/ACL check (owner OR team-member OR admin); a 'forbidden' or
 *  'not-found' PluginError means "no, you can't see this agent" and we
 *  return false. Any OTHER error (e.g. 'unauthenticated', 'no-service',
 *  'init-failed') means the bus or agents plugin is broken — we rethrow so
 *  `writeServiceError` / the http-server's 500 handler can map it instead
 *  of pretending it's a 403 and masking the real bug. */
async function isOwnedBy(
  bus: HookBus,
  ctx: AgentContext,
  agentId: string,
  userId: string,
): Promise<boolean> {
  try {
    await bus.call<{ agentId: string; userId: string }, unknown>(
      'agents:resolve',
      ctx,
      { agentId, userId },
    );
    return true;
  } catch (err) {
    if (
      err instanceof PluginError &&
      (err.code === 'forbidden' || err.code === 'not-found')
    ) {
      return false;
    }
    throw err;
  }
}

/** Inline (duck-typed) view of the routines list/recent-fires/fire-now
 *  service hook outputs — declared here rather than imported from @ax/routines
 *  per Invariant L2. Only the fields we relay to the client are typed; any
 *  extra fields on the wire pass through untouched. */
interface RoutineListItem {
  agentId: string;
---
import { type Plugin, makeAgentContext } from '@ax/core';
import { registerRoutinesAdminRoutes } from './routes.js';

const PLUGIN_NAME = '@ax/routines-admin-routes';

// ---------------------------------------------------------------------------
// @ax/routines-admin-routes
//
// Mounts /settings/routines* on top of the routines facade (@ax/routines).
// Owner-scoped only — /admin/routines* is intentionally not part of this
// package; the Routines admin UI is a per-user surface, not a fleet-wide
// shared-key surface like /admin/credentials.
//
// Duck-typed req/res surface (no @ax/http-server import per Invariant I2).
// No cross-plugin imports per Invariant L2 — `shared.ts` is copied from
// credentials-admin-routes, not imported.
// ---------------------------------------------------------------------------

export function createRoutinesAdminRoutesPlugin(): Plugin {
  const unregisterRoutes: Array<() => void> = [];

  return {
    manifest: {
      name: PLUGIN_NAME,
      version: '0.0.0',
      registers: [],
      // Hard deps. http:register-route comes from @ax/http-server,
      // auth:require-user from @ax/auth-oidc, routines:* from @ax/routines,
      // and agents:resolve from @ax/agents. The topo-sort in bootstrap()
      // ensures these are wired before our init runs.
      calls: [
        'http:register-route',
        'auth:require-user',
        'routines:list',
        'routines:recent-fires',
        'routines:fire-now',
        'agents:resolve',
      ],
      subscribes: [],
    },

    async init({ bus }) {
      const initCtx = makeAgentContext({
        sessionId: 'init',
        agentId: PLUGIN_NAME,
        userId: 'system',
      });
      // Atomic route registration: registerRoutinesAdminRoutes already
      // unwinds internally on partial failure, but we still push into our
      // shutdown-bound list AFTER it returns successfully so a re-init
      // doesn't double-mount.
      try {
        unregisterRoutes.push(
          ...(await registerRoutinesAdminRoutes(bus, initCtx)),
        );
      } catch (err) {
        while (unregisterRoutes.length > 0) {
          const fn = unregisterRoutes.pop();
          try {
            fn?.();
          } catch (unwindErr) {
            // best-effort unwind — log so a transport error in the
            // unwinder doesn't silently leave a dangling route handler
            // behind. console.warn (not ctx.logger): we have no logger
            // available here without a service-call, and the parent
            // failure is what the operator chases first.
            console.warn(
              `[${PLUGIN_NAME}] failed to unregister route during init-unwind: ${
                unwindErr instanceof Error ? unwindErr.message : String(unwindErr)
              }`,
            );
          }
        }
        throw err;
      }
    },

    async shutdown() {
      // Drop routes first so a re-init doesn't trip duplicate-route on the
      // http-server. unregister is idempotent per http-server's contract;
      // we still wrap each call so a transport error doesn't abort the
      // rest of the shutdown sweep.
      while (unregisterRoutes.length > 0) {
        const fn = unregisterRoutes.pop();
        try {
          fn?.();
        } catch (err) {
          // best-effort — log so a transport-side failure during shutdown
          // is visible. The next teardown attempt will still proceed.
          console.warn(
            `[${PLUGIN_NAME}] failed to unregister route during shutdown: ${
              err instanceof Error ? err.message : String(err)
            }`,
          );
        }
      }
    },
  };
}

