1	/**
2	 * Skills wire client — typed wrappers around `/admin/skills*`.
3	 *
4	 * Path convention matches `lib/credentials.ts` (`/admin/...`, no `/api`
5	 * prefix). Server-side routes live in `@ax/skills`.
6	 *
7	 * Wire posture:
8	 *
9	 *   - `credentials: 'include'` on every call so the auth-oidc session
10	 *     cookie flows. Same posture as `lib/credentials.ts`.
11	 *   - `x-requested-with: ax-admin` on writes so requests pass the
12	 *     http-server's CSRF guard. Same posture as `lib/credentials.ts`.
13	 *   - Throws on non-2xx with status + body excerpt.
14	 *   - Returns undefined on 204 (DELETE); returns parsed JSON on 2xx otherwise.
15	 *
16	 * SECURITY NOTE — every endpoint is admin-gated server-side. UI hiding is
17	 * convenience; the gate is on the server.
18	 */
19	
20	import type { SkillDetail, SkillSummary } from '@ax/skills';
21	
22	const writeHeaders = {
23	  'content-type': 'application/json',
24	  'x-requested-with': 'ax-admin',
25	} as const;
26	
27	const csrfHeader = { 'x-requested-with': 'ax-admin' } as const;
28	
29	async function handleResponse(res: Response): Promise<unknown> {
30	  if (res.status === 204) return undefined;
31	  if (!res.ok) {
32	    const excerpt = await res.text().catch(() => '');
33	    throw new Error(`skills API ${res.status}: ${excerpt.slice(0, 200)}`);
34	  }
35	  return res.json();
36	}
37	
38	export async function listSkills(): Promise<SkillSummary[]> {
39	  const res = await fetch('/admin/skills', { credentials: 'include' });
40	  const body = (await handleResponse(res)) as { skills: SkillSummary[] };
41	  return body.skills;
42	}
43	
44	export async function getSkill(skillId: string): Promise<SkillDetail> {
45	  const res = await fetch(`/admin/skills/${encodeURIComponent(skillId)}`, {
46	    credentials: 'include',
47	  });
48	  return (await handleResponse(res)) as SkillDetail;
49	}
50	
51	/**
52	 * Create a skill from a full SKILL.md string (frontmatter fence + body).
53	 * The server splits the fence and validates the manifest.
54	 *
55	 * `opts.defaultAttached` flips the skill onto every agent at session-open
56	 * (admin-only). Skills declaring credential slots cannot be default-attached;
57	 * the server rejects such writes with `default-attached-requires-no-credentials`.
58	 */
59	export async function upsertSkill(
60	  skillMd: string,
61	  opts?: { defaultAttached?: boolean },
62	): Promise<{ skillId: string; created: boolean }> {
63	  const res = await fetch('/admin/skills', {
64	    method: 'POST',
65	    headers: writeHeaders,
66	    credentials: 'include',
67	    body: JSON.stringify({
68	      skillMd,
69	      ...(opts?.defaultAttached !== undefined
70	        ? { defaultAttached: opts.defaultAttached }
71	        : {}),
72	    }),
73	  });
74	  return (await handleResponse(res)) as { skillId: string; created: boolean };
75	}
76	
77	/**
78	 * Update an existing skill identified by `skillId`. The manifest `name`
79	 * field in `skillMd` must match `skillId`; the server enforces this.
80	 */
81	export async function updateSkill(
82	  skillId: string,
83	  skillMd: string,
84	  opts?: { defaultAttached?: boolean },
85	): Promise<{ skillId: string; created: boolean }> {
86	  const res = await fetch(`/admin/skills/${encodeURIComponent(skillId)}`, {
87	    method: 'PUT',
88	    headers: writeHeaders,
89	    credentials: 'include',
90	    body: JSON.stringify({
91	      skillMd,
92	      ...(opts?.defaultAttached !== undefined
93	        ? { defaultAttached: opts.defaultAttached }
94	        : {}),
95	    }),
96	  });
97	  return (await handleResponse(res)) as { skillId: string; created: boolean };
98	}
99	
100	export async function deleteSkill(skillId: string): Promise<void> {
101	  const res = await fetch(`/admin/skills/${encodeURIComponent(skillId)}`, {
102	    method: 'DELETE',
103	    headers: csrfHeader,
104	    credentials: 'include',
105	  });
106	  await handleResponse(res);
107	}
