import { describe, it, expect, beforeAll, afterAll, afterEach, vi } from 'vitest';
import { PostgreSqlContainer, type StartedPostgreSqlContainer } from '@testcontainers/postgresql';
import { Kysely, PostgresDialect, sql } from 'kysely';
import pg from 'pg';
import { runRoutinesMigration, type RoutinesDatabase } from '../migrations.js';
import { createRoutinesStore } from '../store.js';
import { runTickOnce, type FireRoutineFn } from '../tick.js';

pg.types.setTypeParser(20, (v) => Number(v));

let container: StartedPostgreSqlContainer;
let db: Kysely<RoutinesDatabase>;

beforeAll(async () => {
  container = await new PostgreSqlContainer('postgres:16-alpine').start();
  db = new Kysely<RoutinesDatabase>({ dialect: new PostgresDialect({ pool: new pg.Pool({ connectionString: container.getConnectionUri() }) }) });
  await runRoutinesMigration(db);
}, 120_000);

afterEach(async () => {
  await sql`TRUNCATE default_routines_v1 CASCADE`.execute(db);
  await sql`TRUNCATE routines_v1_definitions, routines_v1_fires`.execute(db);
  // Re-seed heartbeat default so each test starts clean
  await sql`INSERT INTO default_routines_v1 (default_routine_id, name, description, spec_hash, trigger_kind, trigger_spec, interval_seconds, silence_token, silence_max, conversation, prompt_body, source_md) VALUES ('default-heartbeat-2026-05-19', 'heartbeat', 'd', 'h', 'interval', '{"kind":"interval","every":"24h"}'::jsonb, 86400, 'HEARTBEAT_OK', 300, 'shared', 'INITIAL PROMPT', 'src')`.execute(db);
});

afterAll(async () => {
  await db.destroy();
  if (container) await container.stop();
});

describe('canary — defaults materialize → claim → fire → override → admin-edit', () => {
  it('drives all four state transitions end-to-end', async () => {
    const store = createRoutinesStore(db);
    const fireSpy = vi.fn<FireRoutineFn>(async () => ({ status: 'ok', error: null, renderedPrompt: 'p' }));

    // -- (1) Materialize --
    const t0 = new Date('2030-01-01T00:00:00Z');
    await runTickOnce({
      store, fire: fireSpy, now: t0,
      claimBatchSize: 50, claimWindowMinutes: 5,
      getAgentIds: async () => ['agt_x'],
    });
    const materialized = await db.selectFrom('routines_v1_definitions')
      .selectAll()
      .where('agent_id', '=', 'agt_x')
      .where('definition_id', 'is not', null)
      .execute();
    expect(materialized).toHaveLength(1);
    expect(materialized[0].path).toMatch(/^default:/);
    expect(materialized[0].next_run_at).toBeNull();
    expect(fireSpy).not.toHaveBeenCalled(); // first tick after materialize; last_run_at null → due is "now" which is t0; we want this materialized but NOT yet fired. Wait — last_run_at is null so COALESCE(last_run_at, created_at) + interval gives a time well in the future. So it shouldn't fire. OK.

    // Force the row to be "due" by setting last_run_at well before t0:
    await db.updateTable('routines_v1_definitions')
      .set({ last_run_at: new Date(t0.getTime() - 25 * 3600 * 1000) }) // 25h ago
      .where('agent_id', '=', 'agt_x')
      .where('definition_id', 'is not', null)
      .execute();

    // -- (2) Claim + fire --
    fireSpy.mockClear();
    await runTickOnce({
      store, fire: fireSpy, now: t0,
      claimBatchSize: 50, claimWindowMinutes: 5,
      getAgentIds: async () => ['agt_x'],
    });
    expect(fireSpy).toHaveBeenCalledTimes(1);
    const firedRow = fireSpy.mock.calls[0][0];
    expect(firedRow.agentId).toBe('agt_x');
    expect(firedRow.path).toMatch(/^default:/);
    expect(firedRow.name).toBe('heartbeat');
    expect(firedRow.promptBody).toBe('INITIAL PROMPT');
    const fires = await db.selectFrom('routines_v1_fires').selectAll().where('agent_id', '=', 'agt_x').execute();
    expect(fires).toHaveLength(1);
    expect(fires[0].status).toBe('ok');

    // -- (3) Override by workspace routine of same name --
    await store.upsert({
      agentId: 'agt_x', path: '.ax/routines/heartbeat.md', authorUserId: 'u',
      name: 'heartbeat', description: 'workspace override', specHash: 'ws-hash',
      trigger: { kind: 'interval', every: '24h' },
      activeHours: null, silenceToken: null, silenceMax: 300,
      conversation: 'per-fire', promptBody: 'WORKSPACE PROMPT',
      nextRunAt: new Date(t0.getTime() - 1000), // already due
    });
    // The default-sourced row is still in the table; make it also "due" again so without the override predicate it would fire too.
    await db.updateTable('routines_v1_definitions')
      .set({ last_run_at: new Date(t0.getTime() - 25 * 3600 * 1000) })
      .where('agent_id', '=', 'agt_x')
      .where('definition_id', 'is not', null)
      .execute();
    fireSpy.mockClear();
    await runTickOnce({
      store, fire: fireSpy, now: t0,
      claimBatchSize: 50, claimWindowMinutes: 5,
      getAgentIds: async () => ['agt_x'],
    });
    // Workspace row fired; default-sourced row did NOT fire.
    const firedPaths = fireSpy.mock.calls.map((c) => c[0].path);
    expect(firedPaths).toContain('.ax/routines/heartbeat.md');
    expect(firedPaths.some((p) => p.startsWith('default:'))).toBe(false);

    // -- (4) Admin edit → refresh updates denormalized copy --
    // Bump default's updated_at past the per-agent row's definition_updated_at, change prompt_body.
    await db.updateTable('default_routines_v1')
      .set({ prompt_body: 'EDITED PROMPT', updated_at: sql`now() + interval '1 hour'` })
      .where('name', '=', 'heartbeat')
      .execute();
    // Delete the workspace override so the default-sourced row could fire (we want to assert refresh, not fire).
    await db.deleteFrom('routines_v1_definitions').where('path', '=', '.ax/routines/heartbeat.md').execute();
    // Advance clock so the default-sourced row is due:
    const t1 = new Date(t0.getTime() + 26 * 3600 * 1000);
    fireSpy.mockClear();
    await runTickOnce({
      store, fire: fireSpy, now: t1,
      claimBatchSize: 50, claimWindowMinutes: 5,
      getAgentIds: async () => ['agt_x'],
    });
    expect(fireSpy).toHaveBeenCalledTimes(1);
    const refreshedRow = fireSpy.mock.calls[0][0];
    expect(refreshedRow.promptBody).toBe('EDITED PROMPT');
  });
});
```

